import React, { useState, useEffect } from 'react';
import {
  Box,
  Button,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Grid,
  Card,
  CardContent,
  Typography,
  IconButton,
  Chip,
  Alert,
  CircularProgress,
  FormControlLabel,
  Switch
} from '@mui/material';
import { Edit as EditIcon, Delete as DeleteIcon } from '@mui/icons-material';
import { api } from '../../services/api';

const PublicationsManager = () => {
  const [publications, setPublications] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingPublication, setEditingPublication] = useState(null);
  const [formData, setFormData] = useState({
    title: '',
    journal: '',
    date: '',
    doi: '',
    description: '',
    tags: [],
    featured: false
  });

  const fetchPublications = async () => {
    try {
      const response = await api.get('/publications');
      const data = response.data;
      setPublications(
        Array.isArray(data)
          ? data
          : data.items || data.data || []
      );
      setError('');
    } catch (err) {
      setError('Failed to fetch publications');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchPublications();
  }, []);

  const handleOpenDialog = (publication = null) => {
    if (publication) {
      setEditingPublication(publication);
      setFormData({
        title: publication.title,
        journal: publication.journal,
        date: publication.date.split('T')[0],
        doi: publication.doi,
        description: publication.description,
        tags: publication.tags,
        featured: publication.featured
      });
    } else {
      setEditingPublication(null);
      setFormData({
        title: '',
        journal: '',
        date: '',
        doi: '',
        description: '',
        tags: [],
        featured: false
      });
    }
    setDialogOpen(true);
  };

  const handleCloseDialog = () => {
    setDialogOpen(false);
    setEditingPublication(null);
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleTagsChange = (e) => {
    const tags = e.target.value.split(',').map(tag => tag.trim());
    setFormData(prev => ({
      ...prev,
      tags
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingPublication) {
        await api.patch(`/publications/${editingPublication._id}`, formData);
      } else {
        await api.post('/publications', formData);
      }
      handleCloseDialog();
      fetchPublications();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to save publication');
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this publication?')) {
      try {
        await api.delete(`/publications/${id}`);
        fetchPublications();
      } catch (err) {
        setError('Failed to delete publication');
      }
    }
  };

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="200px">
        <CircularProgress />
      </Box>
    );
  }

  const publicationsArray = Array.isArray(publications) ? publications : [];

  return (
    <Box>
      {error && (
        <Alert severity="error" sx={{ mb: 2 }}>
          {error}
        </Alert>
      )}

      <Box display="flex" justifyContent="flex-end" mb={2}>
        <Button
          variant="contained"
          color="primary"
          onClick={() => handleOpenDialog()}
        >
          Add Publication
        </Button>
      </Box>

      <Grid container spacing={3}>
        {publicationsArray.map((publication) => (
          <Grid item xs={12} sm={6} md={4} key={publication._id}>
            <Card>
              <CardContent>
                <Typography variant="h6" gutterBottom>
                  {publication.title}
                </Typography>
                <Typography variant="body2" color="text.secondary" gutterBottom>
                  {publication.journal}
                </Typography>
                <Typography variant="body2" color="text.secondary" gutterBottom>
                  {new Date(publication.date).toLocaleDateString()}
                </Typography>
                <Typography variant="body2" color="text.secondary" gutterBottom>
                  DOI: {publication.doi}
                </Typography>
                <Typography variant="body2" paragraph>
                  {publication.description}
                </Typography>
                <Box mt={1}>
                  {Array.isArray(publication.tags) && publication.tags.map((tag, index) => (
                    <Chip
                      key={index}
                      label={tag}
                      size="small"
                      sx={{ mr: 0.5, mb: 0.5 }}
                    />
                  ))}
                </Box>
                <Box mt={2} display="flex" justifyContent="flex-end">
                  <IconButton
                    size="small"
                    onClick={() => handleOpenDialog(publication)}
                  >
                    <EditIcon />
                  </IconButton>
                  <IconButton
                    size="small"
                    onClick={() => handleDelete(publication._id)}
                  >
                    <DeleteIcon />
                  </IconButton>
                </Box>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>

      <Dialog open={dialogOpen} onClose={handleCloseDialog} maxWidth="sm" fullWidth>
        <DialogTitle>
          {editingPublication ? 'Edit Publication' : 'Add Publication'}
        </DialogTitle>
        <DialogContent>
          <Box component="form" onSubmit={handleSubmit} sx={{ mt: 2 }}>
            <TextField
              fullWidth
              label="Title"
              name="title"
              value={formData.title}
              onChange={handleChange}
              margin="normal"
              required
            />
            <TextField
              fullWidth
              label="Journal"
              name="journal"
              value={formData.journal}
              onChange={handleChange}
              margin="normal"
              required
            />
            <TextField
              fullWidth
              label="Date"
              name="date"
              type="date"
              value={formData.date}
              onChange={handleChange}
              margin="normal"
              required
              InputLabelProps={{ shrink: true }}
            />
            <TextField
              fullWidth
              label="DOI"
              name="doi"
              value={formData.doi}
              onChange={handleChange}
              margin="normal"
              required
            />
            <TextField
              fullWidth
              label="Description"
              name="description"
              value={formData.description}
              onChange={handleChange}
              margin="normal"
              required
              multiline
              rows={4}
            />
            <TextField
              fullWidth
              label="Tags (comma-separated)"
              name="tags"
              value={formData.tags.join(', ')}
              onChange={handleTagsChange}
              margin="normal"
              required
            />
            <FormControlLabel
              control={
                <Switch
                  checked={formData.featured}
                  onChange={(e) => setFormData(prev => ({
                    ...prev,
                    featured: e.target.checked
                  }))}
                  name="featured"
                />
              }
              label="Featured"
            />
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleCloseDialog}>Cancel</Button>
          <Button onClick={handleSubmit} variant="contained" color="primary">
            {editingPublication ? 'Update' : 'Add'}
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default PublicationsManager;
